// Rapidmail DOI Webhook Payload parsen
// Rapidmail sendet bei 'confirmed' Event (Double Opt-In Bestätigung)
const body = $input.first().json;

// Debug: Payload loggen
console.log('Rapidmail DOI Payload:', JSON.stringify(body));

// Email extrahieren - mehrere mögliche Formate
const email =
  body.email ||
  body.Email ||
  body.subscriber?.email ||
  body.body?.email ||
  (body.query && body.query.email) ||
  '';

if (!email || !email.includes('@')) {
  throw new Error(`Ungültige Email im DOI Payload: ${JSON.stringify(body)}`);
}

// Name extrahieren
const firstName =
  body.firstname ||
  body.first_name ||
  body.vorname ||
  body.subscriber?.firstname ||
  body.body?.firstname ||
  'Interessent';

// Event-Typ prüfen (Rapidmail: 'confirmed', 'subscribed', 'double_opt_in')
const eventType = body.event || body.type || body.status || 'confirmed';

// Download-URL aus Umgebungsvariable
const downloadUrl = $env.DOWNLOAD_URL || 'https://ai-engineering.at/download/dsgvo-checklist';
const senderEmail = $env.AI_SENDER_EMAIL || 'noreply@ai-engineering.at';
const senderName = $env.AI_SENDER_NAME || 'AI Engineering Austria';

return [{
  json: {
    email: email.toLowerCase().trim(),
    firstName: firstName,
    eventType,
    downloadUrl,
    senderEmail,
    senderName,
    timestamp: new Date().toISOString(),
    rawPayload: body
  }
}];

